-- Nutrition source baseline: USDA FoodData Central / common label averages; portions are app estimates for practical logging.
-- Sport MET baseline: 2024 Compendium of Physical Activities; strength exercise MET values are practical estimates around Compendium strength-training ranges.

update public.nutrition_foods nf
set
  serving_grams = v.serving_grams,
  tags = array(select distinct unnest(coalesce(nf.tags, '{}') || v.tags)),
  updated_at = now()
from (values
  ('rice_cooked', 180::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('pasta_cooked', 180::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('pasta_chicken_onion_cream', 350::numeric, array['portion_revue','plat','portion_estimee']::text[]),
  ('rice_onion_zucchini', 300::numeric, array['portion_revue','plat','portion_estimee']::text[]),
  ('chicken_breast', 130::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('egg', 60::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('fresh_cream', 30::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('muesli', 45::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('belvita', 12.5::numeric, array['portion_revue','portion_un_biscuit','source_etiquette']::text[]),
  ('bread', 60::numeric, array['portion_revue','source_usda_fdc']::text[]),
  ('burger_maison', 300::numeric, array['portion_revue','plat','portion_estimee']::text[])
) as v(key, serving_grams, tags)
where nf.key = v.key
  and nf.user_id is null;

on conflict (key) do update set
  name = excluded.name,
  serving_grams = excluded.serving_grams,
  kcal_per_100g = excluded.kcal_per_100g,
  protein_per_100g = excluded.protein_per_100g,
  carbs_per_100g = excluded.carbs_per_100g,
  fat_per_100g = excluded.fat_per_100g,
  fiber_per_100g = excluded.fiber_per_100g,
  water_ml_per_100g = excluded.water_ml_per_100g,
  tags = excluded.tags,
  is_active = true,
  updated_at = now();

on conflict (key) do update set
  goal = excluded.goal,
  equipment = excluded.equipment,
  activity_key = excluded.activity_key,
  name_fr = excluded.name_fr,
  name_en = excluded.name_en,
  mode = excluded.mode,
  default_reps = excluded.default_reps,
  default_seconds = excluded.default_seconds,
  default_sets = excluded.default_sets,
  default_rest_seconds = excluded.default_rest_seconds,
  distance_m = excluded.distance_m,
  met_value = excluded.met_value,
  tags = excluded.tags,
  sort_order = excluded.sort_order,
  is_active = true,
  updated_at = now();
